mapper.select:
SELECT COALESCE(MAX(sequence_no), 0) + 1
FROM agent_chat_message
WHERE task_id = #{taskId}

SELECT * FROM ( SELECT id, task_id, user_id, sequence_no, role, message_type, content, payload_json, source_event_type, source_id, dedupe_key, created_at, updated_at FROM agent_chat_message WHERE task_id = #{taskId}
AND sequence_no < #{beforeSequenceNo}
AND sequence_no > #{afterSequenceNo}
ORDER BY
sequence_no DESC sequence_no ASC
LIMIT #{limit} ) page_messages ORDER BY sequence_no ASC

SELECT COUNT(*)
FROM agent_chat_message
WHERE task_id = #{taskId}
  AND sequence_no < #{sequenceNo}

SELECT COUNT(*)
FROM agent_chat_message
WHERE task_id = #{taskId}
  AND sequence_no > #{sequenceNo}

SELECT id, task_id, user_id, sequence_no, role, message_type, content, payload_json, source_event_type, source_id, dedupe_key, created_at, updated_at FROM agent_chat_message WHERE task_id = #{taskId} AND id NOT IN ( SELECT id FROM ( SELECT id FROM agent_chat_message WHERE task_id = #{taskId} ORDER BY sequence_no DESC LIMIT #{recentLimit} ) recent_message_ids )
AND sequence_no > ( SELECT sequence_no FROM agent_chat_message WHERE task_id = #{taskId} AND id = #{latestCoveredMessageEndId} )
ORDER BY sequence_no ASC LIMIT #{limit}

SELECT COUNT(*)
FROM agent_chat_message
WHERE task_id = #{taskId}
  AND id NOT IN (
    SELECT id
    FROM (
        SELECT id
        FROM agent_chat_message
        WHERE task_id = #{taskId}
        ORDER BY sequence_no DESC
        LIMIT #{recentLimit}
    ) recent_message_ids
  )

  AND sequence_no > (
      SELECT sequence_no FROM agent_chat_message WHERE task_id = #{taskId} AND id = #{latestCoveredMessageEndId}
  )

SELECT id, task_id, user_id, sequence_no, role, message_type, content, payload_json, source_event_type, source_id, dedupe_key, created_at, updated_at FROM agent_chat_message WHERE task_id = #{taskId} AND (
id = #{anchorMessageId}
sequence_no >= ( SELECT sequence_no FROM agent_chat_message WHERE task_id = #{taskId} AND id = #{coveredMessageStartId} ) AND sequence_no <= ( SELECT sequence_no FROM agent_chat_message WHERE task_id = #{taskId} AND id = #{coveredMessageEndId} )
1 = 0
) ORDER BY sequence_no ASC LIMIT #{limit}

SELECT id, task_id, user_id, sequence_no, role, message_type, content, payload_json, source_event_type, source_id, dedupe_key, created_at, updated_at FROM agent_chat_message WHERE task_id = #{taskId} AND (
sequence_no > ( SELECT sequence_no FROM agent_chat_message WHERE task_id = #{taskId} AND id = #{anchorMessageId} )
sequence_no > ( SELECT sequence_no FROM agent_chat_message WHERE task_id = #{taskId} AND id = #{coveredMessageEndId} )
1 = 0
) ORDER BY sequence_no ASC LIMIT #{limit}
